export const translationDictionary: Record<string, string[]> = {
    // Português : [Inglês, Alemão]
    "máquina": ["machine", "maschine"],
    "receita": ["recipe", "rezept"],
    "parada": ["stop", "stopp"],
    "erro": ["error", "fehler"],
    "iniciar": ["start", "starten"],
    "produção": ["production", "produktion"],
    "estado": ["state", "zustand"],
    "configuração": ["configuration", "konfiguration"],
    "manutenção": ["maintenance", "wartung"],
    "aviso": ["warning", "warnung"],
    "falha": ["failure", "ausfall"],
    "sucesso": ["success", "erfolg"],
    "parâmetro": ["parameter", "parameter"],
    "ajuste": ["adjustment", "einstellung"],
    "monitoramento": ["monitoring", "überwachung"],
    "sistema": ["system", "system"],
    "controle": ["control", "steuerung"],
    "dados": ["data", "daten"],
    "registro": ["log", "protokoll"],
    "análise": ["analysis", "analyse"],
    "tarefa": ["task", "aufgabe"],
    "execução": ["execution", "ausführung"],
    "resultado": ["result", "ergebnis"],
    "rejeito": ["rejection", "ablehnung"],
    "tabela de rejeição": ["rejection table", "ausleittisch"],

    // Adicione mais termos conforme necessário
};

/**
 * Recebe uma palavra-chave e retorna um array com ela e suas traduções.
 */
export function getTranslations(keyword: string): string[] {
    const lower = keyword.toLowerCase();
    if (translationDictionary[lower]) {
        return [lower, ...translationDictionary[lower]];
    }
    return [lower];
}

export { };
